from flask import Flask, request, jsonify
import logging
import datetime
import os
import hashlib
import hmac

app = Flask(__name__)

# Set up logging configuration
logging.basicConfig(filename='application.log', level=logging.INFO,
                    format='%(asctime)s - %(levelname)s - %(message)s')

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    email = data.get('email')
    
    # Validate user input
    if not all([username, password, email]):
        return jsonify({'error': 'Missing required fields'}), 400
    
    # Hash and verify password (simplified for example purposes)
    hashed_password = hashlib.sha256(password.encode()).hexdigest()
    if hmac.compare_digest(hashed_password, data.get('hashed_password')):
        logging.info(f'Login successful - username: {username}, email: {email}')
        return jsonify({'message': 'Logged in successfully'}), 200
    else:
        # Log failed login attempt
        ip_address = request.remote_addr
        user_agent = request.headers.get('User-Agent')
        logging.warning(f'Login failed - username: {username}, IP address: {ip_address}, User Agent: {user_agent}')
        return jsonify({'error': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)